import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Box } from '@mui/material';

import { TrophyProgressCard } from 'pages/Playstation/components/trophy-progress-card';

import { TrophyGame } from '../../../service/types';

export function TrophyTitle({ game }: { game: TrophyGame }) {
  const navigate = useNavigate();

  const titlePath = `game/${game.id}/platform/${game.platform}`;
  return (
    <Box onClick={() => navigate(titlePath)}>
      <TrophyProgressCard
        image={game.image}
        title={game.title}
        progress={game.progress}
        trophyCount={game.trophyCount}
        earnedCount={game.earnedCount}
        platform={game.platform}
      />
    </Box>
  );
}
